// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract DarkWaveToken is ERC20, ERC20Burnable, Ownable {
    uint256 public constant INITIAL_SUPPLY = 1_000_000_000 * 10**18;

    mapping(address => StakeInfo[]) public stakes;

    struct StakeInfo {
        uint256 amount;
        uint256 startTime;
        uint256 lockPeriod;
        bool claimed;
    }

    event Staked(address indexed user, uint256 amount, uint256 lockPeriod);
    event Unstaked(address indexed user, uint256 amount, uint256 rewards);

    constructor() ERC20("DarkWave Token", "DWT") Ownable(msg.sender) {
        _mint(msg.sender, INITIAL_SUPPLY);
    }

    function stake(uint256 amount, uint256 lockPeriod) external returns (bool) {
        require(amount >= 100 * 10**18, "Minimum stake is 100 DWT");
        require(lockPeriod == 30 days || lockPeriod == 90 days || lockPeriod == 365 days, "Invalid lock period");

        _transfer(msg.sender, address(this), amount);

        stakes[msg.sender].push(StakeInfo({
            amount: amount,
            startTime: block.timestamp,
            lockPeriod: lockPeriod,
            claimed: false
        }));

        emit Staked(msg.sender, amount, lockPeriod);
        return true;
    }

    function unstake(uint256 stakeId) external returns (bool) {
        require(stakeId < stakes[msg.sender].length, "Invalid stake ID");
        StakeInfo storage stakeInfo = stakes[msg.sender][stakeId];
        require(!stakeInfo.claimed, "Already claimed");
        require(block.timestamp >= stakeInfo.startTime + stakeInfo.lockPeriod, "Still locked");

        uint256 rewards = calculateRewards(stakeInfo.amount, stakeInfo.lockPeriod);
        stakeInfo.claimed = true;

        _transfer(address(this), msg.sender, stakeInfo.amount);
        _mint(msg.sender, rewards);

        emit Unstaked(msg.sender, stakeInfo.amount, rewards);
        return true;
    }

    function calculateRewards(uint256 amount, uint256 lockPeriod) public pure returns (uint256) {
        uint256 apy;
        if (lockPeriod == 30 days) apy = 6;
        else if (lockPeriod == 90 days) apy = 9;
        else if (lockPeriod == 365 days) apy = 12;

        return (amount * apy * lockPeriod) / (365 days * 100);
    }

    function claimRewards() external returns (uint256) {
        uint256 totalRewards = 0;
        for (uint256 i = 0; i < stakes[msg.sender].length; i++) {
            StakeInfo storage stakeInfo = stakes[msg.sender][i];
            if (!stakeInfo.claimed && block.timestamp >= stakeInfo.startTime + stakeInfo.lockPeriod) {
                totalRewards += calculateRewards(stakeInfo.amount, stakeInfo.lockPeriod);
            }
        }
        if (totalRewards > 0) {
            _mint(msg.sender, totalRewards);
        }
        return totalRewards;
    }
}
